// Script Continued Below
(function executeRule(current, previous /*null when async*/) {
	// RJ - PSD - STRY0063760 - Copy Shared Documents from Task Tree to Process
	var grTopTask = new GlideRecord('x_153465_discovert_route_task_instance');
	if(grTopTask.get(current.getValue("original_tasker_saved_to_process"))){
		var fromConfigId = gs.getProperty("x_153465_discovert.DocIntSharedDocumentsViewSysIDTasks");
		var toConfigId = gs.getProperty("x_153465_discovert.DocIntProcessSharedDocumentsViewSysIDTasks");
		var tDS = new taskerDocumentScripts();
		tDS.copyDocuments (grTopTask, current, 'Shared', fromConfigId, toConfigId);

		// RJ - PSD - STRY0063760 - now copy attachments from tree to process
		var grTaskTree = new GlideRecord('x_153465_discovert_task_tree');
		if(grTaskTree.get(grTopTask.getValue("u_task_tree"))){
			tDS.copyAttachments(grTaskTree, current, 'Shared');
		}


	}
})(current, previous);
